package protocol

import (
	"encoding/hex"
	"testing"

	"github.com/stretchr/testify/assert"
)

var initHex1 = "f7f46d697b715c696f5c0808082808094a5c20e8"
var initHex1Xor = "fffc656173795461675c000000200001425428e0"
var initHex2 = "f7f46d697b715c696f5c08080b80080d4a5c9878"

var whiteFullHex = ""
var whiteFullHexXor = ""
var blackFullHex = ""

var macAddrHex = "3D:00:00:7B:D5:F8"

func TestMarshal(t *testing.T) {
	allZero := make([]byte, 296*128)
	allOne := make([]byte, 296*128)
	for i := range allOne {
		allOne[i] = 0xFF
	}
	packets, err := Marshal(allOne, allZero, macAddrHex)
	assert.NoError(t, err)
	assert.Len(t, packets, 2)
	assert.Equal(t, initHex1, hex.EncodeToString(packets[0]))
	assert.Equal(t, blackFullHex, hex.EncodeToString(packets[1]))
}

func TestMarshalInit(t *testing.T) {
	macAddr, err := parseMac(macAddrHex)
	assert.NoError(t, err)
	assert.Equal(t, initHex1, hex.EncodeToString(marshalInit(32, macAddr)))
	assert.Equal(t, initHex2, hex.EncodeToString(marshalInit(904, macAddr)))
}

func TestXorMagic(t *testing.T) {
	macAddr, err := parseMac(macAddrHex)
	assert.NoError(t, err)

	in, err := hex.DecodeString(initHex1)
	assert.NoError(t, err)
	xorMagic(in, macAddr)
	actualHex := hex.EncodeToString(in)
	assert.Equal(t, initHex1Xor, actualHex)

	in, err = hex.DecodeString(whiteFullHex)
	assert.NoError(t, err)
	xorMagic(in, macAddr)
	actualHex = hex.EncodeToString(in)
	assert.Equal(t, whiteFullHexXor, actualHex)
}

func TestCrc(t *testing.T) {
	data, err := hex.DecodeString(whiteFullHexXor)
	assert.NoError(t, err)
	actual := crc16(data[0 : len(data)-2])
	assert.Equal(t, []byte{0x12, 0xb9}, actual)
}
